// Filter rows where Status = 'New Lead' and Message Sent is empty
const allRows = $input.all();
const newLeads = allRows.filter(row => {
  const status = (row.json['Status'] || '').trim();
  const messageSent = (row.json['Message Sent'] || '').trim();
  return status === 'New Lead' && messageSent === '';
});

console.log(`New leads to process: ${newLeads.length} of ${allRows.length} total rows`);
return newLeads;

// Generate opener for this lead via Claude API
const lead = $input.first().json;

const bio = (lead['Notes'] || '').trim();
const businessName = (lead['Business Name'] || lead['Instagram Handle'] || 'there').trim();
const industry = (lead['Type'] || 'business').trim();
const location = (lead['Location'] || 'London').trim();
const followers = lead['Followers'] || 'unknown';

const prompt = `You are writing a cold Instagram DM opener for a sales outreach campaign.

Lead details:
- Business Name: ${businessName}
- Industry: ${industry}
- Location: ${location}
- Bio: ${bio || 'No bio available'}
- Followers: ${followers}

Write ONE short opener DM using this exact formula:
"Hey [Business Name] - saw [something specific from their bio or profile]. [One genuine observation about it]. Would this be the best place to ask you a quick question?"

Rules you must follow exactly:
- Reference something REAL and SPECIFIC from the bio above - not generic
- The observation must be genuine - find one thing worth saying
- Under 3 lines total
- NEVER mention AI, automation, agencies, or technology
- NEVER use generic compliments (no "Love what you're doing", "Amazing content", "Great work", etc)
- End with ONE question only
- If the bio contains no useful specific information to reference, output exactly this text: REVIEW NEEDED - add profile detail before sending

Output the DM text only. No explanation. No surrounding quotes.`;

const response = await this.helpers.httpRequest({
  method: 'POST',
  url: 'https://api.anthropic.com/v1/messages',
  headers: {
    'x-api-key': 'YOUR_ANTHROPIC_API_KEY',
    'anthropic-version': '2023-06-01',
    'content-type': 'application/json'
  },
  body: {
    model: 'claude-haiku-4-5-20251001',
    max_tokens: 150,
    messages: [{ role: 'user', content: prompt }]
  },
  json: true
});

const opener = response.content[0].text.trim();

return [{
  json: {
    ...lead,
    opener: opener,
    generated_at: new Date().toISOString().split('T')[0]
  }
}];

// Collect all processed leads and build one email summary
const items = $input.all();

const openerLines = items.map((item, i) => {
  const handle = item.json['Instagram Handle'] || 'unknown';
  const name = (item.json['Business Name'] || handle).trim();
  const type = item.json['Type'] || '';
  const opener = item.json.opener || '';
  const needsReview = opener.startsWith('REVIEW NEEDED');
  const flag = needsReview ? ' [NEEDS REVIEW]' : '';
  return `${i + 1}. ${name} (${handle}) — ${type}${flag}\n   ${opener}`;
});

const reviewCount = items.filter(i => (i.json.opener || '').startsWith('REVIEW NEEDED')).length;
const readyCount = items.length - reviewCount;
const date = new Date().toISOString().split('T')[0];

const subject = `Zizi — ${items.length} opener${items.length !== 1 ? 's' : ''} ready (${date})`;

const body = `Workflow 2 — Opener Generation Complete

Date: ${date}
Total processed: ${items.length}
Ready to send: ${readyCount}
Needs manual review: ${reviewCount}

---

${openerLines.join('\n\n')}

---

All openers written to Google Sheet under "Message Sent" column.
Status updated to "Opener Ready".

Zizi: review each opener, personalise if needed, then send from the lead's profile.
Flag anything that looks wrong before sending.`;

return [{
  json: {
    subject: subject,
    body: body,
    count: items.length,
    ready: readyCount,
    review: reviewCount
  }
}];
